-- ============================================================
-- CHAPTER 2: Power Chords & Rock Techniques
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, target_notes, accuracy_threshold, estimated_minutes, is_premium) values

  ('e1c20000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000002', 'Power Chord Fundamentals',
   'What power chords are, why they work with distortion, and the two core shapes that unlock rock and metal.',
   1, 'theory',
   '{"intro":"Power chords are the foundation of rock, punk, and metal guitar. Unlike open chords, power chords contain only two notes — the root and the fifth — which prevents the dissonance that full chords create under heavy distortion.","steps":[{"title":"What Is a Power Chord?","body":"A power chord (sometimes written as E5, A5, etc.) contains only the root note and the perfect fifth. By omitting the third (which determines major/minor), power chords sound massive and neutral under high gain. The number 5 indicates the fifth interval."},{"title":"Why No Third?","body":"Under distortion, the third interval creates intermodulation artifacts — ghost notes and dissonant overtones that sound muddy. Dropping the third cleans up the signal dramatically. This is why rock guitarists live on power chords."},{"title":"Two Core Shapes","body":"The E-string root shape places your index on the low E string and your ring finger two frets higher on the A string. The A-string root shape places your index on the A string and your ring finger two frets higher on the D string. These two shapes alone let you play power chords anywhere on the neck."},{"title":"Navigation on the Fretboard","body":"The root note is the note on your index finger. Move this shape to fret 5 on the low E (A note) and you have A5. Move to fret 3 on the A string (C note) and you have C5. The chromatic scale along strings 6 and 5 is your map."}],"tips":["Keep your fretting hand relaxed — power chords need less pressure than barre chords","Mute the unused strings by lightly touching them with the underside of your index finger"]}',
   null, null, null, 0, 20, true),

  ('e1c20000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000002', 'E5 & A5 Power Chords',
   'Hands-on with the two essential power chord shapes — precise finger placement and clean articulation.',
   2, 'chord',
   '{"intro":"Time to put theory into practice. This lesson drills the E5 and A5 power chord shapes with precise finger placement so every note rings clean and powerful.","steps":[{"title":"E5 Shape (E-String Root)","body":"Place your index finger on string 6, fret 3. Place your ring finger on string 5, fret 5. Optionally add your pinky on string 4, fret 5 for a fuller sound. Mute strings 1-3 by resting your index finger lightly across them. Strum only strings 6 and 5 — or 6 through 4 if adding the octave. This is G5."},{"title":"A5 Shape (A-String Root)","body":"Place your index finger on string 5, fret 3. Place your ring finger on string 4, fret 5. Add pinky on string 3, fret 5 for the octave. String 6 is muted by the tip of your index finger resting against it. Strings 1 and 2 are muted by your index finger pad. This is C5."},{"title":"Clean Articulation Check","body":"Pluck only your target strings. If you hear any unwanted string ringing, adjust your muting. Every note should punch through with percussive attack. If the tone is fuzzy, check finger arch and pressure — the tip, not the pad, should be on the string."},{"title":"Shifting Between Shapes","body":"Play G5 (E-form at fret 3), slide up to A5 at fret 5, then jump to C5 (A-form at fret 3). Keep your wrist loose — tension kills speed. Practice this 3-chord sequence with a metronome at 80 BPM."}],"tips":["Your picking hand should strike with conviction — power chords need attack to sound aggressive","For palm-muted chugging (next lesson), the same shapes apply with your palm resting on the bridge"]}',
   'G5', '[{"string":6,"fret":3,"finger":1},{"string":5,"fret":5,"finger":3}]', null, 75, 25, true),

  ('e1c20000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000002', 'Palm Muting',
   'The right-hand technique that gives rock and metal its percussive, punchy character.',
   3, 'exercise',
   '{"intro":"Palm muting transforms power chords from ringing sustains into tight, percussive chugs. This exercise builds the right-hand muscle memory that defines the sound of modern rock and metal rhythm guitar.","steps":[{"title":"The Right-Hand Position","body":"Rest the fleshy edge of your picking palm on the strings, directly over the bridge saddles. Too far forward and you will kill the note entirely. Too far back and you will not mute at all. Start with your palm touching the strings at the bridge, then nudge forward millimeter by millimeter until you hear the note sustain briefly before dying. This is the sweet spot."},{"title":"Chugging on a Single String","body":"Play the open low E string with palm mute, alternating downstrokes and upstrokes at 90 BPM in 8th notes. Each stroke should produce a tight \"chk-chk-chk-chk\" sound. Focus on consistency — every stroke should have identical attack and duration. Record yourself to check."},{"title":"Power Chord Palm Muting","body":"Apply your E5 power chord (already fretted) and add the palm mute. Downstroke-downstroke-up-down pattern at 100 BPM. The first two downstrokes should be heavy and muted. The up-down pair should let the chord ring slightly. This is the classic metal gallop."},{"title":"The Release","body":"The magic of palm muting is the contrast between muted and open. Play four muted strokes, then release your palm fully on beat 4 and let the chord ring. This tension-and-release is the core of rock rhythm guitar. Practice with G5 and C5, switching between them while maintaining the mute pattern."}],"tips":["Palm muting at the bridge requires almost no pressure — the weight of your hand alone is usually enough","Different bridge types (Floyd Rose, Tune-o-matic, Telecaster) have different sweet spots — experiment with your specific guitar"]}',
   null, null, null, 80, 30, true),

  ('e1c20000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000002', 'Rock Progressions',
   'String power chords together into authentic rock rhythms with transitions, rests, and dynamics.',
   4, 'exercise',
   '{"intro":"Now that you can play individual power chords with palm muting, it is time to chain them into actual rock progressions — the backbone of thousands of songs from AC/DC to Green Day.","steps":[{"title":"The Classic I-IV-V in E","body":"Play E5 (E-form, fret 0 open or fret 12), A5 (A-form, fret 0 or fret 7), and B5 (E-form, fret 7). Each chord gets 4 beats of eighth-note downstrokes at 120 BPM. Focus on smooth shifts — your wrist and forearm should guide the movement, not your fingers individually."},{"title":"The I-bVII-bVI Progression","body":"This is the Smoke on the Water lineage. In key of E: E5 (fret 0/12), D5 (E-form fret 10), C5 (E-form fret 8). Down-down-up pattern on each. The flat VII and flat VI give rock its darker, blues-derived edge."},{"title":"Pedal Tone Riffing","body":"Keep your index anchored on string 6 fret 3 (G). While it stays, move your ring finger among string 5 frets 5, 3, and 2. This creates G5, a dissonant G diminished, and an open G-like sound — a signature rock riffing technique used by Metallica and Pantera."},{"title":"The Stop-and-Start","body":"Play G5 for 3 beats, then full silence (both hands mute everything) for beat 4. Resume with C5 on beat 1. This rhythmic punctuation — the \"rest\" — is as important as the notes. A band needs to hit these stops together. Practice with a metronome and count out loud."},{"title":"Dynamic Shaping","body":"Play a 4-bar progression (G5 - C5 - D5 - C5) where bar 1 is lightly palm-muted, bar 2 opens up slightly, bar 3 is full open chords, and bar 4 returns to tight mutes. This is how rock songs build energy across verses and choruses."}],"tips":["Keep your thumb anchored behind the neck throughout all shifts — it is your pivot point","Double-stop slides (sliding a power chord shape up into position) add instant rock swagger to your transitions"]}',
   null, null, null, 75, 35, true),

  ('e1c20000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000002', 'The Minor Pentatonic Intro',
   'The most important scale in rock music — five notes, five positions, infinite possibilities.',
   5, 'theory',
   '{"intro":"The minor pentatonic scale is the most-used scale in rock, blues, and pop lead guitar. Its five notes (root, flat third, fourth, fifth, flat seventh) naturally avoid clashing with any underlying chord.","steps":[{"title":"The Five Notes","body":"In A minor pentatonic: A (root), C (flat third), D (fourth), E (fifth), G (flat seventh). That is only five notes, yet they power virtually every guitar solo in classic rock. The gaps between notes — those big intervals — are what give the pentatonic its vocal, singing quality."},{"title":"Position 1 (The Go-To Shape)","body":"At fret 5: string 6 frets 5 and 8, string 5 frets 5 and 7, string 4 frets 5 and 7, string 3 frets 5 and 7, string 2 frets 5 and 8, string 1 frets 5 and 8. This box shape sits exactly at the 5th fret with the root (A) on strings 6, 4, and 1. Memorize this shape cold — it is the shape you will use more than any other."},{"title":"Why Pentatonic Works","body":"The missing notes in pentatonic are the ones that create tension — the 2nd (9th) and the 6th. By leaving them out, every note you play sounds intentional and consonant over any chord in the minor key. You can close your eyes and play any note from the scale over an Am chord and it will work."},{"title":"The Blues Connection","body":"The minor pentatonic is the blues scale minus the flat fifth (blue note). In a later chapter you will add that one chromatic passing tone and unlock the full blues vocabulary. For now, master the pure five-note scale and learn to make it sing through bends and vibrato."}],"tips":["Spend a week playing only Position 1 before exploring other positions — depth before breadth","Sing the notes as you play them. Your ear needs to lead, not just your fingers"]}',
   null, null, ARRAY['A','C','D','E','G'], 0, 25, true);

-- ============================================================
-- CHAPTER 3: Advanced Strumming & Rhythm
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, target_notes, accuracy_threshold, estimated_minutes, is_premium) values

  ('e1c30000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000003', 'Syncopation Basics',
   'Understanding off-beat accents and how syncopation creates rhythmic excitement and groove.',
   1, 'theory',
   '{"intro":"Syncopation is the deliberate accenting of weak beats or off-beats. It is what makes a rhythm feel funky, surprising, and alive. Mastering syncopation separates rhythm guitarists from strummers.","steps":[{"title":"The Grid","body":"In 4/4 time, the strong beats are 1 and 3. The weak beats are 2 and 4. Syncopation places accent on the weak beats or on the \"and\" between beats. Count 1-and-2-and-3-and-4-and. The numbers are downbeats; the \"ands\" are upbeats. Accenting an \"and\" is the most common form of syncopation."},{"title":"Reggae-Style Syncopation","body":"Reggae guitarists strum on beats 2 and 4 (or the \"and\" after beat 2 and beat 4), actively avoiding beats 1 and 3. This creates the characteristic lilt. To feel it: strum a G chord with downstrokes only on beats 2 and 4 while counting 1-2-3-4. The silence on 1 and 3 creates rhythmic tension."},{"title":"Anticipated Chord Changes","body":"Rather than changing chords directly on beat 1, change on the \"and\" of beat 4 — half a beat early. This is called anticipating the change. It drives the music forward and is a hallmark of funk, R&B, and modern pop production."},{"title":"Tied Notes Across Bar Lines","body":"Syncopation can extend a note from a weak beat into the next strong beat by tying. Hold a chord that was struck on beat 4-and through beat 1 of the next bar. The listener expects a strong accent on beat 1; not hearing it creates a powerful displacement effect."}],"tips":["Practice counting \"1 and 2 and 3 and 4 and\" out loud while tapping your foot on 1-2-3-4 — the foot keeps the pulse, the counting reveals the subdivisions","Syncopation only works against a steady pulse — if your timing drifts, the effect is lost"]}',
   null, null, null, 0, 25, true),

  ('e1c30000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000003', '16th Note Strumming',
   'Master fast, precise 16th-note patterns — the rhythmic engine of funk, disco, and fast rock.',
   2, 'exercise',
   '{"intro":"Sixteenth notes divide each beat into four equal parts. Counting: 1-e-and-a 2-e-and-a 3-e-and-a 4-e-and-a. Sixteen strums per bar. At faster tempos, the pick hand becomes a machine.","steps":[{"title":"The Continuous Motion Exercise","body":"Set a metronome to 60 BPM. Keeping your strumming hand moving in a constant down-up-down-up pattern (16th notes), but only actually striking the strings on certain passes. This is ghost strumming — your hand moves continuously, but you only make contact when needed. This is the secret to effortless 16th note playing."},{"title":"The Disco Pattern","body":"On an open Am chord: down on 1, up on the \"a\" of 1, down on 2-e, down on 3, up on the \"a\" of 3, down on 4-e. The pattern is: D---U-DD---U-D where dashes are ghost strokes. This is the rhythm behind Stayin Alive, Get Lucky, and countless dance tracks."},{"title":"The 16th-Note Rock Chug","body":"On a power chord: D-D-D- (rest). Three consecutive 16th-note downstrokes, then silence for the remaining 13 sixteenths. At 100 BPM this creates the aggressive staccato pulse of modern rock. Start slow, build speed gradually. Clean articulation at 80 BPM beats sloppy playing at 120."},{"title":"Combining 8th and 16th","body":"Play two bars of straight 8th notes, then switch to 16th notes for two bars, and back. This tests your ability to double and halve your picking speed on command. Critical for songs that shift rhythmic density between verse and chorus."}],"tips":["A thin, flexible pick (0.60mm or less) makes 16th-note strumming much easier than a heavy pick","Your wrist should move in tiny circles — big movements create fatigue and timing errors at speed"]}',
   null, null, null, 75, 35, true),

  ('e1c30000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000003', 'Swing & Shuffle Rhythms',
   'How swing feel alters note timing and why the metronome is only half the story.',
   3, 'theory',
   '{"intro":"Swing is the rhythmic feel where pairs of eighth notes are played unevenly — the first longer than the second. This creates a loping, triplet-based groove that defines jazz, blues, and classic rock and roll.","steps":[{"title":"What Is Swing?","body":"Instead of dividing a beat evenly into two eighth notes (50/50), swing divides it into a triplet-based ratio — roughly 2/3 + 1/3. The first note is held for two triplet subdivisions, the second for one. Written music often shows straight eighths with the instruction \"swing.\" Try saying \"doo-bah, doo-bah\" to vocalize the rhythm."},{"title":"The Shuffle","body":"A shuffle is swing applied to every beat consistently. It is the rhythmic feel behind Pride and Joy (Stevie Ray Vaughan), La Grange (ZZ Top), and most blues. On guitar, shuffle strumming uses continuous down-up strokes where the upstroke lands on the shorter third of the triplet. The pick hand never stops — it is always moving."},{"title":"Swing vs Straight","body":"Play an Am chord with straight eighth notes (even down-up) for 4 bars. Then switch to swung eighths for 4 bars. The straight feel sounds rigid and precise. The swing feel sounds relaxed and breathing. Neither is better — each serves different musical purposes. The skill is being able to switch at will."},{"title":"Swing in Different Tempos","body":"At slow tempos (60-80 BPM), swing is pronounced — the long-short difference is dramatic. At fast tempos (200+ BPM), swing naturally straightens because the physical mechanics of picking group the notes more evenly. Bebop and fast swing jazz live in this transitional zone."}],"tips":["Set a metronome to click only on beats 2 and 4 at half speed — this forces you to feel the swing internally","Listen to Freddie Green (Count Basie Orchestra) — his four-to-the-bar comping is the encyclopedia of swing rhythm guitar"]}',
   null, null, null, 0, 25, true),

  ('e1c30000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000003', 'Funk Strumming',
   'Lock into the groove with 16th-note ghost strums, muted scratches, and tight left-hand control.',
   4, 'exercise',
   '{"intro":"Funk guitar is 90% left-hand muting and 10% notes. The iconic percussive \"chicka-chicka\" sound comes from pressing and releasing chords in rhythm while the right hand maintains continuous 16th-note motion.","steps":[{"title":"The Scratch Technique","body":"Lightly rest your fretting hand across all six strings — not pressing hard enough to fret any note, just enough to produce a percussive scratch when strummed. Your right hand maintains a constant 16th-note down-up strum. Now, press a chord shape (start with Am7: 5th fret barre) only on specific 16th-note subdivisions, releasing immediately back to the scratch. The chord blooms for a moment, then vanishes."},{"title":"The Classic Funk Pattern","body":"On an E9 chord (open E with middle finger on string 5 fret 2, ring on string 4 fret 2, index on string 3 fret 1): scratch-scratch-CHORD-scratch-scratch-CHORD-scratch-CHORD. The chord lands on the \"e\" of 1 and the \"and\" of 2. This is the Nile Rodgers / Chic / Prince rhythm."},{"title":"Single-Note Stabs","body":"Instead of full chords, press just one note of the chord — say, the root on string 5 — while the rest of the strings remain muted. Alternate between single-note stabs and full chord releases. This dynamic contrast between thin and thick textures is classic James Brown guitarist Jimmy Nolen."},{"title":"The 16th-Note Groove Endurance Test","body":"Pick a funk pattern and play it for 4 minutes straight at 100 BPM without stopping. The goal is not to play it perfectly — the goal is to learn what your right arm feels like after 2 minutes of continuous 16th notes. Funk guitar is a physical endurance sport. Build it gradually."}],"tips":["A compressor pedal (or plugin) evens out the volume between scratches and chords, making funk guitar sound instantly more professional","The left hand does more work in funk than the right — learn to love the muting dance"]}',
   null, null, null, 80, 35, true),

  ('e1c30000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000003', 'Odd Time Signatures',
   'Breaking free from 4/4 — understanding 3/4, 6/8, 5/4, 7/8 and how to make them feel natural.',
   5, 'theory',
   '{"intro":"Most popular music is in 4/4, but some of the most compelling compositions use odd time signatures to create a sense of motion and surprise. Understanding them unlocks progressive rock, folk traditions, and modern composition.","steps":[{"title":"3/4 and 6/8","body":"3/4 has three quarter-note beats per bar (ONE-two-three). 6/8 has two beats, each subdivided into three eighth notes (ONE-and-a TWO-and-a). They sound similar but feel different — 3/4 is waltz-like, 6/8 has a rolling compound feel. Strumming pattern for 3/4: D-DU-D (basically two bars of 4/4 with the last beat removed). For 6/8: D-DU-DU (a lilting triplet feel)."},{"title":"5/4 — The Dave Brubeck Groove","body":"5/4 is five beats per bar, typically felt as 3+2 or 2+3. Take Five uses 3+2 grouping. To feel it: count ONE-two-three-ONE-two while tapping the pulse. Strum an Am chord accenting beats 1 and 4. The asymmetry creates a constant forward momentum — you never quite settle."},{"title":"7/8 — The Progressive Rock Signature","body":"7/8 has seven eighth notes grouped as 3+2+2, 2+2+3, or 2+3+2. Pink Floyd''s Money riff is 7/8 (3+2+2). Tap it: ONE-two-three ONE-two ONE-two. The irregular groupings make 7/8 feel urgent and propulsive. Practice strumming with the groupings — accent the first of each subgroup."},{"title":"Making Odd Meters Feel Natural","body":"The key to odd meters is internalizing the pulse so it does not feel like counting. Listen to Money. Clap the 7-beat cycle until you can feel it without counting. Then strum along with just downstrokes on the accents. Your body needs to feel the cycle as one unified gesture, not seven separate beats."}],"tips":["Start by walking to the pulse of odd-time songs — if you cannot move to it, you cannot play it","Odd-time signatures often feel awkward because your brain defaults to groups of 2 or 4 — that discomfort is the learning"]}',
   null, null, null, 0, 30, true);

-- ============================================================
-- CHAPTER 4: Scales & Fretboard Mastery
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, target_notes, accuracy_threshold, estimated_minutes, is_premium) values

  ('e1c40000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000004', 'CAGED System',
   'The five open chord shapes (C, A, G, E, D) as a complete map of the fretboard.',
   1, 'theory',
   '{"intro":"The CAGED system reveals that the five basic open chord shapes — C, A, G, E, and D — can be moved up the neck with barres to play any chord in five different positions. It is the most important fretboard visualization tool in guitar pedagogy.","steps":[{"title":"The Five Shapes","body":"Each letter in CAGED names an open chord shape: C shape (root on string 5), A shape (root on string 5), G shape (root on string 6), E shape (root on string 6), D shape (root on string 4). When you play these shapes in order moving up the neck as barre chords, they spell C-A-G-E-D and connect end-to-end, covering the entire fretboard."},{"title":"Connecting C to A","body":"Play a C chord in open position (C shape). Now play C as an A-form barre chord at fret 3. The high notes of the C shape overlap with the low notes of the A shape. This overlap is the key — every CAGED shape shares notes with its neighbors, creating a continuous chain of chord tones across the neck."},{"title":"Connecting A to G","body":"From C played as A-form at fret 3, move to C as a G-form barre chord at fret 5. This shape is physically demanding (it spans 4 frets) but it connects the A and E forms. The fingering: index bars fret 5, middle on string 4 fret 7, ring on string 3 fret 8, pinky on string 2 fret 9."},{"title":"The Full CAGED Map for C Major","body":"C shape: open position. A shape: fret 3. G shape: fret 5. E shape: fret 8. D shape: fret 10. Then it repeats — C shape again at fret 12. Practice playing a C major chord in all five positions. Each sounds like C, but with a different voicing and character. This is the foundation for chord melody, soloing, and fretboard navigation."}],"tips":["Do not try to learn all five shapes at once — master one new CAGED position per week","Say the note names out loud as you play through each position — this builds fretboard knowledge alongside the shapes"]}',
   null, null, null, 0, 35, true),

  ('e1c40000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000004', 'Major Scale Patterns',
   'Playing the major scale across the fretboard in five interconnected positions.',
   2, 'exercise',
   '{"intro":"The major scale is the parent scale of Western music — every other scale and mode derives from it. Learning the five CAGED-based positions of the major scale gives you complete fretboard fluency.","steps":[{"title":"G Major — Position 1 (E-Form)","body":"Starting on string 6, fret 3 (G): frets 3-5-7 on string 6. String 5: frets 3-5-7. String 4: frets 3-5. String 3: frets 4-5-7. String 2: frets 5-7-8. String 1: frets 5-7-8. Play ascending and descending, alternate picking every note. This is the most commonly taught major scale pattern and lives directly over the E-form barre chord."},{"title":"G Major — Position 2 (D-Form)","body":"Starting on string 6, fret 5: frets 5-7-8. String 5: frets 5-7-9. String 4: frets 5-7-9. String 3: frets 5-7. String 2: frets 7-8. String 1: frets 7-8-10. This position connects to Position 1 — notice the overlap. The high end of Position 1 becomes the low end of Position 2."},{"title":"G Major — Position 3 (C-Form)","body":"Starting on string 6, fret 7: frets 7-8-10. String 5: frets 7-9-10. String 4: frets 7-9-10. String 3: frets 7-9. String 2: frets 8-10-12. String 1: frets 8-10-12. Practice all three positions in sequence: play Position 1 ascending, slide up into Position 2, slide into Position 3. Do not stop — the goal is seamless position shifting."},{"title":"The Three-Note-Per-String Approach","body":"An alternative to CAGED positions is playing exactly three notes per string, every string. For G major: string 6: 3-5-7, string 5: 3-5-7, string 4: 4-5-7, string 3: 4-5-7, string 2: 5-7-8, string 1: 5-7-8. This approach is favored by shred guitarists because it enables consistent, symmetrical picking patterns across all strings."}],"tips":["Practice each position with a metronome at 60 BPM in quarter notes, then eighth notes, then triplets, then sixteenths — only increase tempo when every note is clean","Play the G major chord, then play the G major scale position that lives directly beneath it — seeing the chord inside the scale is the CAGED insight"]}',
   null, null, ARRAY['G','A','B','C','D','E','F#'], 75, 40, true),

  ('e1c40000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000004', 'Minor Pentatonic Positions',
   'Master all five positions of the minor pentatonic scale — the vocabulary of rock and blues soloing.',
   3, 'exercise',
   '{"intro":"You have already learned Position 1 of the minor pentatonic. Now connect all five positions across the fretboard to unlock the full range of melodic possibilities.","steps":[{"title":"A Minor Pentatonic — All Five Positions","body":"Position 1 (E-form): root on string 6 fret 5. Frets 5-8 on strings 6 and 2; 5-7 on strings 5, 4, 3, 1. Position 2 (D-form): start string 6 frets 8-10, then expands upward. Position 3 (C-form): start string 6 frets 10-12-13. Position 4 (A-form): start string 6 frets 12-15. Position 5 (G-form): start string 6 frets 15-17. Each position connects at shared notes with its neighbor."},{"title":"Horizontal Playing","body":"Instead of staying in one box, play the A minor pentatonic on a single string. String 6: frets 5, 8, 10, 12, 15, 17 (A, C, D, E, G, A). Then descend. Now do the same on string 5, then string 4. Horizontal playing breaks you out of box thinking and forces you to hear the scale as a melodic line, not a visual shape."},{"title":"Position Shifting with Slides","body":"Play Position 1 ascending. When you reach the high A on string 1 fret 5, slide up to fret 8 (C) and continue into Position 2. Descend through Position 2, and at the lowest A (string 6 fret 8), slide down to fret 5 and land back in Position 1. This creates a continuous, connected solo line that spans multiple positions."},{"title":"The One-String Improv Challenge","body":"Improvise a 30-second solo using only string 2 (B string). You have frets 5, 8, 10, 12, 15, 17 available (all A minor pentatonic notes). No other strings allowed. This forces melodic thinking — you cannot rely on shapes, only on hearing where the next note should go."}],"tips":["Position 1 is your home base — always know how to return to it from any other position","The pentatonic boxes overlap in two places each — learn the overlap notes and the transitions become seamless"]}',
   null, null, ARRAY['A','C','D','E','G'], 75, 35, true),

  ('e1c40000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000004', 'Blues Scale with Bends',
   'Adding the flat fifth to the minor pentatonic and using bends to make the blues scale sing.',
   4, 'exercise',
   '{"intro":"The blues scale is the minor pentatonic plus one note — the flat fifth (also called the blue note). Combined with expressive bends, this six-note scale is the emotional core of blues, rock, and R&B guitar.","steps":[{"title":"The Six-Note Blues Scale","body":"A blues scale: A (root), C (flat third), D (fourth), Eb (flat fifth — the blue note), E (fifth), G (flat seventh). In Position 1 at fret 5: add Eb at string 5 fret 6 and string 3 fret 5 (bent slightly). The blue note is a spice — use it sparingly, passing through it, not landing and staying on it."},{"title":"Whole-Step Bends","body":"Place finger 3 on string 3, fret 7 (D note). Pick it, then push the string upward (toward the ceiling for standard right-hand guitar) until the pitch rises a full whole step — matching the E note at fret 9. This bend is the single most iconic sound in blues guitar. Use your wrist, not your fingers, to push the string. Support the bend with fingers 1 and 2 behind finger 3."},{"title":"Unison Bends","body":"Fret string 2 at fret 8 (G) with finger 1. Fret string 3 at fret 7 (D) with finger 3 and bend a whole step up to E. Pick both strings simultaneously — you hear a stationary G on string 2 and a rising D-to-E on string 3. The two notes clash slightly, then converge. This is pure Hendrix/SRV vocabulary."},{"title":"Bending into the Blue Note","body":"The most expressive use of the flat fifth is to bend into it. On string 3, fret 5 (C), bend a quarter step — not all the way to C#, but somewhere in between. This microtonal region is where the blues lives. There is no correct pitch — it is a feeling. Your ear decides when it is right."}],"tips":["The bend must reach pitch before you can use it musically — practice bending to a target note, holding it, and checking against the fretted note at the target fret","Heavier string gauges (.010 or .011) make bends harder but sustain better and produce richer tone — find your balance"]}',
   null, null, ARRAY['A','C','D','Eb','E','G'], 80, 35, true),

  ('e1c40000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000004', 'Connecting Scale Shapes',
   'Seamlessly moving between scale positions using slides, position shifts, and diagonal patterns.',
   5, 'exercise',
   '{"intro":"Sounding like a musician rather than a scale exerciser means connecting positions smoothly. This lesson focuses on the transitions — the glue between boxes that makes your playing flow across the neck.","steps":[{"title":"The Diagonal Pentatonic","body":"Play the A minor pentatonic moving diagonally up the neck: string 6 fret 5 (A), string 6 fret 8 (C), shift to string 5 fret 5 (D), string 5 fret 7 (E), shift to string 4 fret 7 (G) — you are now in Position 2. Continue this diagonal pattern, shifting position every two strings. This creates a fluid, wandering path rather than a rigid box."},{"title":"Slide Transitions","body":"Choose your slide moments deliberately. When moving from Position 1 to Position 2, slide finger 3 from string 1 fret 8 up to fret 10 rather than lifting and repositioning. The slide announces the position change as a musical event, not a mechanical necessity. Practice deciding in advance where you will slide."},{"title":"Two-String Horizontal Runs","body":"Play a five-note ascending run on strings 3 and 2: string 3 frets 5-7-9, then string 2 frets 5-8-10. This covers one and a half octaves in a compact, legato-friendly pattern. Practice these two-string runs through every position pair — they form the connective tissue of fast, fluid solos."},{"title":"The Full-Neck Run","body":"Starting at string 6 fret 5 (Position 1), play ascending through all five positions of A minor pentatonic without stopping, ending at string 1 fret 17. Use slides between positions. Then descend back to the starting note. Your goal is to make the journey sound like one continuous musical line, not five disconnected segments."}],"tips":["Your thumb position needs to shift as you move up the neck — keep it centered behind the neck at all times, not hooked over","Think of the fretboard as one long continuous strip, not five separate blocks — visualize the notes, not the boxes"]}',
   null, null, null, 75, 35, true);

-- ============================================================
-- CHAPTER 5: Chord Progression Harmony
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, target_notes, accuracy_threshold, estimated_minutes, is_premium) values

  ('e1c50000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000005', 'Roman Numeral Analysis',
   'Analyzing chord progressions with Roman numerals — the universal language of harmony.',
   1, 'theory',
   '{"intro":"Roman numeral analysis is how musicians communicate chord progressions regardless of key. Once you think in numbers instead of letter names, you can transpose any song instantly and understand why certain progressions work.","steps":[{"title":"Building Chords from the Major Scale","body":"In any major key, build a triad on each scale degree: I (tonic, major), ii (supertonic, minor), iii (mediant, minor), IV (subdominant, major), V (dominant, major), vi (submediant, minor), vii° (leading tone, diminished). In G major: G, Am, Bm, C, D, Em, F#dim. Upper case = major, lower case = minor, ° = diminished."},{"title":"Primary Chords: I, IV, V","body":"The I, IV, and V chords are the pillars of tonal music. They contain every note of the major scale between them. I establishes home. IV creates a sense of departure. V creates maximum tension demanding resolution back to I. The I-IV-V-I cadence is the DNA of Western harmony."},{"title":"The vi Chord and the Axis Progression","body":"The vi chord (relative minor) is the most common substitution for I because they share two notes. I-V-vi-IV is the most used progression in 21st-century pop. In G: G-D-Em-C. This progression is so common it is called the Axis Progression or the Pop-Punk Progression."},{"title":"Analyzing a Real Progression","body":"Take G-Em-C-D7. Label it: I-vi-IV-V7. Now play it in C: C-Am-F-G7. Then in D: D-Bm-G-A7. The numbers stay the same. The chords change with the key. You can now play this progression in any key without memorizing new chord names — just apply the numbers."}],"tips":["Writing Roman numerals above song lyrics is the fastest way to build a repertoire you can play in any key","Major chords feel bright and resolved (I, IV, V). Minor chords feel melancholic or pensive (ii, iii, vi). This emotional mapping is why numbers matter"]}',
   null, null, null, 0, 30, true),

  ('e1c50000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000005', '7th Chords',
   'Major 7, minor 7, dominant 7, and half-diminished — adding the fourth note that transforms harmony.',
   2, 'chord',
   '{"intro":"Triads are three-note chords. Add the seventh scale degree and you unlock a richer harmonic palette. The quality of that seventh — major, minor, or dominant — defines the emotional character of the chord.","steps":[{"title":"Major 7th (Cmaj7)","body":"Root, major third, perfect fifth, major seventh. Cmaj7: fingers 1-3 on strings 4-3-2 frets 2-4-3, with string 5 open and strings 1 and 5 ringing. The sound is lush, dreamy, slightly melancholic despite being a major chord. Type artists: bossa nova, neo-soul, 80s pop ballads."},{"title":"Dominant 7th (G7)","body":"Root, major third, perfect fifth, flat seventh. G7: finger 1 on string 1 fret 1, the rest matching an open G shape. The flat seventh creates tension that demands resolution to the tonic (C). V7-I is the strongest cadence in Western music. G7 to C is the defining resolution of the blues."},{"title":"Minor 7th (Am7)","body":"Root, minor third, perfect fifth, flat seventh. Am7: fingers 1 and 2 on strings 4 and 3 frets 2 and 2, with strings 1, 2, and 5 open. The minor seventh adds smoothness to the minor triad — less tragic, more contemplative. Am7 and Em7 are the mellow backbone of acoustic songwriting."},{"title":"Half-Diminished (Bm7b5)","body":"Root, minor third, flat fifth, flat seventh. Bm7b5: index bars strings 1-4 at fret 1, middle on string 2 fret 2, ring on string 4 fret 3. This chord lives on the vii° degree and sounds tense, unresolved, and harmonically sophisticated. It is the ii chord in minor keys and the gateway to jazz harmony."}],"tips":["The seventh is the note that gives the chord its flavor — always identify which note in the chord is the seventh and sing it","Start by learning the open 7th chord shapes (G7, Cmaj7, Am7, D7, Em7, Bm7b5) before moving to barre voicings"]}',
   'G7', '[{"string":6,"fret":3,"finger":2},{"string":5,"fret":2,"finger":1},{"string":1,"fret":1,"finger":1}]', null, 80, 35, true),

  ('e1c50000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000005', 'Common Progressions I-IV-V-vi',
   'Playing and internalizing the most common chord progression in popular music in multiple keys.',
   3, 'exercise',
   '{"intro":"I-V-vi-IV is everywhere. With these four chords you can play Let It Be, With or Without You, Dont Stop Believin, and hundreds more. This exercise drills the progression in three keys with different voicings.","steps":[{"title":"Key of G: G-D-Em-C","body":"Play each chord for two bars at 80 BPM with a simple D-DU-UD strum. Focus on smooth transitions. The G-to-D change uses an anchor finger (finger 3 stays on string 2 fret 3 for both chords). Em-to-C shares no fingers — practice this pair separately for 2 minutes."},{"title":"Key of C: C-G-Am-F","body":"The same progression, different key. C-G transition: lift fingers 1 and 3 while keeping finger 2 anchored as a guide finger between string 4 fret 2 and string 6 fret 3. Am to F: these are the two chords that require the most barre-like thinking for intermediate players. Practice Am-to-F 20 times."},{"title":"Key of D: D-A-Bm-G","body":"D to A: fingers 1, 2, and 3 shift from a triangle to a line — a shape change, not just a position change. Bm to G: Bm is a barre chord (A-form at fret 2), G is open. This is the hardest pair in the progression. Practice Bm-G-Bm-G at half tempo."},{"title":"Capo and Transposition","body":"Place a capo at fret 2 and play the G shapes (G-D-Em-C). You are now in the key of A. Capo at fret 5 with G shapes = key of C. This is how professional guitarists play in any key while using only open chord shapes. The capo is not cheating — it is efficient."}],"tips":["Sing the bass notes (lowest string played) of each chord as you change — this builds ear training into your chord practice","Once you have the progression under your fingers, close your eyes and play it — letting go of visual dependence"]}',
   null, null, null, 80, 35, true),

  ('e1c50000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000005', 'Secondary Dominants',
   'Using dominant chords outside the key to create temporary tension and colorful harmonic movement.',
   4, 'theory',
   '{"intro":"A secondary dominant is a dominant seventh chord that resolves to a chord other than the tonic. It temporarily tonicizes another chord in the key, adding color and forward motion to progressions.","steps":[{"title":"What Is a Secondary Dominant?","body":"In the key of C, the dominant is G7 (V7), which resolves to C (I). A secondary dominant is the V7 of some other chord in the key. V7/ii = A7 resolving to Dm. V7/vi = E7 resolving to Am. V7/IV = C7 resolving to F. Each borrowed dominant briefly makes its target chord feel like home."},{"title":"V7/vi — The Most Common Secondary Dominant","body":"In key of C: play C - E7 - Am. The E7 is not in the key of C (it contains G#, which is not a C major note). That G# pulls strongly up to A, the root of Am. This creates a dramatic arrival on the vi chord that feels both surprising and inevitable. You hear this in Creep (Radiohead): G-B-C-Cm."},{"title":"The Chain of Dominants","body":"A series of secondary dominants: C - A7 - D7 - G7 - C. Each chord is the V7 of the next. A7 resolves to Dm (or D7), D7 resolves to G7, G7 resolves to C. This is the ragtime and jazz progression, used in Five Foot Two and I Got Rhythm."},{"title":"Voice Leading Secondary Dominants","body":"The magic of secondary dominants is in the voice leading — how individual notes move. In C to A7, the G (5th of C) stays while the C moves to C#, E moves to E. Only one note changes. Smooth voice leading makes the chromaticism feel natural rather than jarring."}],"tips":["To find the secondary dominant of any chord: count up 5 scale degrees from that chord''s root and make it a dominant 7th","Secondary dominants are the first harmonic device that makes your chord progressions sound professionally composed rather than randomly assembled"]}',
   null, null, null, 0, 30, true),

  ('e1c50000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000005', 'Chord Substitutions',
   'Replacing chords with alternatives that share function — the art of harmonic variety.',
   5, 'theory',
   '{"intro":"Chord substitutions let you replace a chord with a related one that serves the same harmonic function. This is how jazz musicians generate endless variety from simple progressions and how songwriters create unexpected emotional turns.","steps":[{"title":"Diatonic Substitution — The iii for I","body":"The I chord (G: G-B-D) and the iii chord (G: Bm: B-D-F#) share two notes. In many contexts, iii can substitute for I, creating a more ambiguous, floating harmony. A G-Am-Bm-C progression replaced as Bm-Am-Bm-C softens the tonic arrival and sounds more introspective."},{"title":"The vi for I","body":"The vi chord (relative minor) shares two notes with I and is the most common substitution. G - Em (both contain G and B). vi-I-vi-I creates a bittersweet oscillation that never quite commits to major or minor. Used extensively by The Beatles and Elliott Smith."},{"title":"Tritone Substitution","body":"Replace any dominant 7th chord with another dominant 7th whose root is a tritone (3 whole steps) away. G7 (G-B-D-F) shares the same tritone interval (B-F) with Db7 (Db-F-Ab-Cb). G7 and Db7 can substitute for each other. This creates chromatic bass movement: Dm7-G7-C becomes Dm7-Db7-C — the bass walks down by half-step."},{"title":"The IV for ii Substitution","body":"ii and IV share two notes and both function as subdominant (they lead to V). In key of C: Dm7 (D-F-A-C) and Fmaj7 (F-A-C-E) share F, A, and C. They are nearly the same chord with a different bass note. Substituting IV for ii (or vice versa) changes the bass movement without changing the harmonic function."}],"tips":["Start with simple substitutions — replace I with vi in a verse for a change of emotional color before returning to I for the chorus","Every substitution changes the bass line. The bass movement is often the most noticeable difference — listen for it"]}',
   null, null, null, 0, 30, true);

-- ============================================================
-- CHAPTER 6: Fingerpicking Mastery
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, target_notes, accuracy_threshold, estimated_minutes, is_premium) values

  ('e1c60000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000006', 'Travis Picking',
   'The alternating bass thumb pattern that defines American folk and country fingerpicking.',
   1, 'exercise',
   '{"intro":"Travis picking, named after Merle Travis, is a fingerpicking technique where the thumb alternates between two (or three) bass strings while the fingers pick melody notes on the treble strings. The thumb is the metronome — steady, automatic, relentless.","steps":[{"title":"Thumb Independence","body":"Assign your thumb (p) to strings 6, 5, and 4. On an open C chord: thumb plucks string 5, then thumb plucks string 4, then thumb returns to string 5, then string 4. Repeat this alternating bass pattern until it becomes automatic. The thumb never stops — it is the heartbeat."},{"title":"Adding the Index Finger","body":"While your thumb maintains the alternating bass on strings 5 and 4, add your index finger plucking string 2 (open B) between thumb strokes. The pattern becomes: thumb-5, index-2, thumb-4, index-2. Count: 1-and-2-and. This is the fundamental Travis picking pattern. On an Am chord: thumb alternates string 5 and 4, index plucks string 2."},{"title":"Adding the Middle Finger","body":"Add your middle finger on string 1. The pattern expands: thumb-5, index-2, thumb-4, middle-1. Repeat over C and Am. The thumb remains the anchor. The fingers dance above it, adding melody. This three-finger pattern is the core vocabulary of Dust in the Wind, Landslide, and Blackbird-style playing."},{"title":"Chord Changes While Picking","body":"Practice the full pattern (thumb-index-thumb-middle) on C for two bars, then shift to Am while the thumb never stops. The thumb lands on the appropriate bass strings for each chord: C uses strings 5 and 4 (C and E bass notes). Am uses strings 5 and 4 (A and E). The fingers stay on strings 1-2 for both chords."}],"tips":["Practice with a metronome — the thumb must land exactly on the beat. If the thumb is steady, everything else falls into place","Start at 60 BPM. Speed up only when you can hold a conversation while playing — that proves the thumb is truly automatic"]}',
   null, null, null, 85, 40, true),

  ('e1c60000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000006', 'Alternating Bass',
   'Independent bass lines that walk between chord changes — the foundation of country and folk guitar.',
   2, 'exercise',
   '{"intro":"Alternating bass takes Travis picking a step further by having the bass note change within a single chord — typically alternating between the root and the fifth. This creates the walking feel that defines country, folk, and ragtime guitar.","steps":[{"title":"Root-Fifth Alternation","body":"On a G chord: thumb alternates between string 6 (G, the root) and string 4 (D, the fifth). On a C chord: thumb alternates string 5 (C, root) and string 4 (E, the third — but string 6 is open G which works well too). The alternation creates a two-note bass melody beneath the chord."},{"title":"Walking Between Chords","body":"When moving from G to C, instead of jumping directly, walk the bass. G chord (thumb on string 6), then thumb on string 4 (transition note), then land on C chord with thumb on string 5. The bass line: G (string 6) → D (string 4) → C (string 5). A melodic bass line that connects the two chords."},{"title":"The Country Bass Pattern","body":"Combine alternating bass with a simple melody on the treble strings. On G: thumb on string 6, index-middle pinch on strings 1 and 2. Then thumb on string 4, index on string 2. The bass alternates root-fifth-root-fifth while the treble plays a syncopated counter-rhythm. This is the Johnny Cash / Carter Family sound."},{"title":"Bass Runs","body":"Between chord changes, play a short run of single bass notes (thumb only) before arriving at the next chord. From G to C: thumb plays string 6 fret 3 (G), string 5 fret 2 (B), string 5 fret 3 (C — arrival). This three-note run connects G to C melodically. Practice creating bass runs between every pair of chords you know."}],"tips":["Know the root and fifth of every chord — this is the bass-player mindset. The root is the chord name; the fifth is 7 semitones (or one string lower, two frets higher) up","Record just your bass line (mute the treble strings) — it should sound like a simple, coherent melody on its own"]}',
   null, null, null, 80, 35, true),

  ('e1c60000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000006', 'Percussive Fingerstyle',
   'Adding slap, tap, and body percussion to fingerpicking for modern acoustic grooves.',
   3, 'exercise',
   '{"intro":"Percussive fingerstyle turns the guitar into a drum kit and melody instrument simultaneously. Pioneered by Michael Hedges and popularized by Andy McKee and Jon Gomm, this technique adds rhythm section to your solo acoustic performance.","steps":[{"title":"The Thumb Slap","body":"Slap the bass strings with the side of your thumb — a quick, percussive strike that produces a thud rather than a note. The motion comes from rotating your wrist, not from your elbow. On beats 2 and 4 of a 4/4 bar, slap strings 6 and 5 together. This is your snare drum."},{"title":"The Nail Tap","body":"Tap the guitar body with your fingernails (middle and ring fingers) on the top bout, near the upper edge. This produces a higher percussive click — your hi-hat. Combine: thumb slap on beats 2 and 4, nail taps on every 8th note. You now have a drum groove happening while your left hand frets chords."},{"title":"Integrating Slap with Fingerpicking","body":"On beat 1: thumb plucks bass (string 5). On beat 1-and: nail tap. On beat 2: thumb slap (strings 5-6 muted). On beat 2-and: nail tap. On beat 3: index plucks string 2. On beat 3-and: nail tap. On beat 4: thumb slap. On beat 4-and: nail tap. This pattern produces melody, bass, and percussion simultaneously."},{"title":"The Harmonic Tap","body":"Gently tap directly over the 12th fret with your picking-hand index finger. This produces a bell-like harmonic. Combine with thumb slap and fretted notes to create a shimmering, multi-layered texture. The harmonic tap works on any string at frets 12, 7, and 5 — experiment."}],"tips":["Percussive guitar is easier on a guitar with a pickup system so the body hits are audible — but practice unplugged first to build real dynamics","Start with just the percussion groove (no chords) for 2 minutes — lock in the feel before adding the left hand"]}',
   null, null, null, 80, 35, true),

  ('e1c60000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000006', 'Classical Arpeggios',
   'PIMA right-hand technique and the discipline of classical arpeggio patterns.',
   4, 'exercise',
   '{"intro":"Classical guitar uses a formalized right-hand system: p (thumb, pulgar), i (index, indice), m (middle, medio), a (ring, anular). These four letters describe every pluck. Learning classical arpeggios builds precision, independence, and articulation control.","steps":[{"title":"PIMA Basic Pattern","body":"Assign strings: p = string 6 or 5 (alternating bass), i = string 3, m = string 2, a = string 1. The fundamental pattern on an open Am chord: p (string 5), i (string 3), m (string 2), a (string 1), m (string 2), i (string 3). This is p-i-m-a-m-i — a six-note repeating cycle. Play at 60 BPM, each note equal duration."},{"title":"Giulianis 120 Right-Hand Studies","body":"Mauro Giuliani wrote 120 arpeggio patterns for the right hand. Pattern 1: p-i-m-a-m-i repeated. Pattern 2: p-a-m-i-m-a (reverse). Pattern 3: p-i-m-a-i-m-a-i. Practice patterns 1-10 over an Am chord. Each pattern trains a different combination of finger independence. The patterns never change — only the chords change."},{"title":"Rest Stroke vs Free Stroke","body":"Rest stroke (apoyando): after plucking, the finger comes to rest on the adjacent string. Produces a fuller, louder tone. Used for melody. Free stroke (tirando): the finger plucks and curls into the palm without touching adjacent strings. Used for arpeggios and chords. Practice both on a single open string to hear the tonal difference."},{"title":"Dynamic Control","body":"Play the p-i-m-a-m-i pattern while making only the a-finger note loud (accent). Then only the p note soft. Then crescendo across the six notes, then decrescendo. Classical guitarists spend years refining this dynamic independence — each finger should be capable of producing a different volume simultaneously."}],"tips":["File your nails: classical tone comes from nail-and-flesh contact. Shaping nails with 500-grit sandpaper produces a smooth, singing tone","Practice PIMA patterns while watching TV or having a conversation — the right hand must become autonomous"]}',
   null, null, null, 85, 40, true),

  ('e1c60000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000006', 'Creating Original Patterns',
   'Moving beyond memorized patterns to improvise fingerpicking arrangements in real time.',
   5, 'exercise',
   '{"intro":"The goal of fingerpicking technique is not to play pre-written patterns — it is to express musical ideas spontaneously through your fingers. This lesson teaches you how to generate original patterns by thinking melodically and rhythmically.","steps":[{"title":"Melody-First Thinking","body":"Instead of starting with a pattern, start with a melody. Hum or sing a simple phrase. Find those notes on strings 1-3. Now ask: what bass notes support this melody? Add thumb on the downbeats. The pattern emerges from the melody, not the other way around. This is the compositional approach to fingerpicking."},{"title":"Pattern Variation","body":"Take the basic p-i-m-a pattern and vary one element: change which string the thumb hits (5 vs 4 vs 6). Change the rhythm (make the i-m-a notes double-time). Change the order (p-i-a-m instead of p-i-m-a). Deliberately altering one variable at a time generates dozens of patterns from one archetype."},{"title":"Harmonic Rhythm Variation","body":"Over a G chord, play one pattern for one bar, then a different pattern for the second bar. The chord stays the same, but the picking pattern changes. This creates variation without changing harmony — essential for preventing repetitive-sounding accompaniment. Write down three different patterns for G and cycle through them."},{"title":"Improvising a Fingerpicking Arrangement","body":"Choose a simple chord progression: G-Em-C-D. Play through it four times. Each time, vary the picking pattern: first pass simple p-i-m-a, second pass add melody notes on the treble strings, third pass include percussive thumb slaps, fourth pass return to simplicity. This is how solo acoustic performers turn 4 chords into a 3-minute performance."}],"tips":["Record yourself improvising patterns and listen back — you will notice habits you want to break and ideas you want to develop","The best original patterns come from messing up — when your finger accidentally hits the wrong string, lean into it. That is a new pattern being born"]}',
   null, null, null, 80, 35, true);

-- ============================================================
-- CHAPTER 7: Music Theory Expansion
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, target_notes, accuracy_threshold, estimated_minutes, is_premium) values

  ('e1c70000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000007', 'Modes of the Major Scale',
   'Ionian, Dorian, Phrygian, Lydian, Mixolydian, Aeolian, Locrian — the seven colors of the major scale.',
   1, 'theory',
   '{"intro":"Modes are the major scale starting from a different note. Each mode has a distinct emotional flavor — from the bright, floating Lydian to the dark, tense Locrian. Understanding modes unlocks modal jazz, progressive rock, and film scoring vocabulary.","steps":[{"title":"The Seven Modes","body":"Play C major (C-D-E-F-G-A-B-C). Now play the same notes starting from D: D-E-F-G-A-B-C-D. That is D Dorian — a minor mode with a raised sixth. Starting from E: E Phrygian — a darker minor mode with a flat second. Each starting point produces a different interval pattern and a unique emotional color."},{"title":"Mode Formulas","body":"Think of modes as alterations to major or natural minor. Ionian = major scale (1-2-3-4-5-6-7). Mixolydian = major with flat 7th (1-2-3-4-5-6-b7). Lydian = major with sharp 4th (1-2-3-#4-5-6-7). Aeolian = natural minor (1-2-b3-4-5-b6-b7). Dorian = natural minor with raised 6th (1-2-b3-4-5-6-b7). Phrygian = natural minor with flat 2nd (1-b2-b3-4-5-b6-b7). Locrian = natural minor with flat 2nd and flat 5th (1-b2-b3-4-b5-b6-b7)."},{"title":"The Characteristic Notes","body":"Each mode has one or two notes that define its sound. Lydian: the #4 creates an ethereal, floating quality (think The Simpsons theme opening). Mixolydian: the b7 creates bluesy, grounded major (Sweet Home Alabama). Dorian: the natural 6 over a minor chord creates sophisticated, jazzy minor (Oye Como Va). Phrygian: the b2 creates exotic, Spanish/Middle Eastern tension."},{"title":"Modal Brightness Spectrum","body":"Arrange modes from brightest to darkest: Lydian (#4), Ionian (major), Mixolydian (b7), Dorian (b3, natural 6), Aeolian (b3, b6), Phrygian (b2, b3, b6, b7), Locrian (b2, b3, b5, b6, b7). Each step down the brightness spectrum adds one more flat (or removes one sharp). This ordering helps you internalize the modal colors."}],"tips":["Learn one mode per week. Play its scale, improvise over its characteristic chord, and listen to a song in that mode. Depth over breadth.","Modes are not scales to memorize — they are moods to feel. Play D Dorian over a D minor vamp and notice how the B natural (raised 6th) \"brightens\" the minor sound"]}',
   null, null, null, 0, 35, true),

  ('e1c70000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000007', 'Intervals Deep Dive',
   'The building blocks of every chord and melody — recognizing intervals by ear and on the fretboard.',
   2, 'theory',
   '{"intro":"Intervals are the distance between any two notes, measured in semitones. They are the atoms of music. A chord is nothing but stacked intervals. A melody is a sequence of intervals. Master intervals and you master the language of music.","steps":[{"title":"The 12 Intervals (Ascending)","body":"Minor 2nd (1 semitone): Jaws theme. Major 2nd (2): Happy Birthday. Minor 3rd (3): Greensleeves opening. Major 3rd (4): Oh When the Saints. Perfect 4th (5): Here Comes the Bride. Tritone (6): The Simpsons. Perfect 5th (7): Star Wars. Minor 6th (8): The Entertainer. Major 6th (9): NBC jingle. Minor 7th (10): Star Trek. Major 7th (11): Superman theme. Octave (12): Somewhere Over the Rainbow."},{"title":"Interval Shapes on Guitar","body":"On a single string: each fret = one semitone (minor 2nd). Two frets = major 2nd. Three frets = minor 3rd. Four frets = major 3rd. Five frets = perfect 4th. Seven frets = perfect 5th. Twelve frets = octave. On adjacent strings (same fret): strings 6-5, 5-4, 4-3, 2-1 = perfect 4th. Strings 3-2 = major 3rd. These geometric relationships are the fretboard''s organizing principle."},{"title":"Harmonic vs Melodic Intervals","body":"Play C and E simultaneously (harmonic interval) — you hear a major 3rd, a consonant, bright sound. Play C then E separately (melodic interval) — your ear connects the two pitches into the same relationship. Both matter. Harmonic intervals build chords. Melodic intervals build melodies. The ear processes them identically."},{"title":"Consonance and Dissonance","body":"Perfect unison, octave, perfect 5th, and perfect 4th are perfect consonances. Major and minor 3rds and 6ths are imperfect consonances. Major and minor 2nds and 7ths and the tritone are dissonances. Dissonance is not bad — it creates tension that consonance resolves. Music is the journey from dissonance to consonance and back."}],"tips":["Learn each interval by associating it with a song you know — the opening two notes of every melody encode an interval relationship","On the guitar, the visual shapes of intervals are your superpower — you can see a perfect 5th (one string down, two frets higher) without counting semitones"]}',
   null, null, null, 0, 35, true),

  ('e1c70000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000007', 'Ear Training — Intervals & Chords',
   'Building the ability to identify intervals, chord qualities, and progressions by ear alone.',
   3, 'exercise',
   '{"intro":"The ear is the ultimate musical instrument. This lesson provides a structured approach to ear training — moving from identifying simple intervals to recognizing chord qualities and common progressions.","steps":[{"title":"Interval Recognition Drill","body":"Have a partner (or an ear training app like Tenuto or Functional Ear Trainer) play two notes. Identify the interval. Start with just three intervals: perfect 5th (consonant, hollow), major 3rd (bright, happy), and minor 3rd (dark, sad). Once you can identify these three reliably, add perfect 4th and major 2nd. Build gradually — 3 intervals mastered beats 12 intervals confused."},{"title":"Chord Quality Recognition","body":"Listen to a single chord — can you tell if it is major, minor, dominant 7th, diminished, or augmented? The major chord sounds happy and stable. Minor sounds sad. Dominant 7th sounds bluesy and tense — it wants to resolve. Diminished sounds unstable and scary. Augmented sounds dreamy and unsettled. Practice with random chord playback."},{"title":"Progression Recognition — I-IV-V","body":"Play I-IV-V-I in G (G-C-D-G). Listen deeply. Now play I-IV-V-I in C (C-F-G-C). The pattern is identical despite different notes. Your ear must learn to hear function, not pitch. Practice: close your eyes, have someone play a I-IV-V in a random key, and identify which chord is which by its role."},{"title":"The Diatonic Chord Quiz","body":"In the key of G, play any two chords from the diatonic set (G, Am, Bm, C, D, Em, F#dim). Can you identify which chord is being played? Start with just I, IV, and V. Add vi next. Then ii. Then iii. The vii° is rare and distinctive — you will know it when you hear it."}],"tips":["15 minutes of focused ear training daily outperforms 2 hours once a week — consistency is everything for aural development","Sing everything: sing the intervals, sing the chord tones, sing the bass movement. If you cannot sing it, you cannot truly hear it"]}',
   null, null, null, 80, 35, true),

  ('e1c70000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000007', 'Modal Soloing',
   'Improvising over chord progressions using modal thinking — choosing the right mode for each chord.',
   4, 'exercise',
   '{"intro":"Modal soloing means choosing a mode that fits the chord progression and improvising within that modal color. This moves you beyond pentatonic boxes into harmonically intentional, colorful soloing.","steps":[{"title":"Dorian Over Minor Chords","body":"Dorian is the go-to mode for minor 7th chords in funk, jazz, and rock. Over an Am7 vamp (Am7-D7), play A Dorian: A-B-C-D-E-F#-G. The F# (raised 6th) is the characteristic note — it sounds sophisticated and jazzy compared to the natural minor. Santana built a career on Dorian."},{"title":"Mixolydian Over Dominant Chords","body":"Over a G7 chord, play G Mixolydian: G-A-B-C-D-E-F. The F natural (flat 7th) is the defining note of Mixolydian and perfectly matches the G7 chord (which contains F). Mixolydian is the mode of choice for blues-based rock and jam band soloing (Grateful Dead, Allman Brothers)."},{"title":"Lydian Over Major Chords","body":"Over a Cmaj7 chord, play C Lydian: C-D-E-F#-G-A-B. The F# (sharp 4th) creates a floating, ethereal tension. Use it sparingly — it is a spice note. Steve Vai and Joe Satriani use Lydian extensively for its otherworldly quality. Even a single Lydian passing note can transform a predictable major-key solo."},{"title":"Switching Modes Mid-Progression","body":"Over ii-V-I in C (Dm7-G7-Cmaj7): play D Dorian over Dm7, G Mixolydian over G7, C Ionian over Cmaj7. These three modes all contain the exact same notes (C major) — but emphasizing different chord tones against each chord creates the illusion of modal shifts. Start by targeting the 3rd and 7th of each chord on strong beats."}],"tips":["Playing modally means listening to the chord and responding. Do not just run the scale — target the chord tones (1, 3, 5, 7) on the downbeats and use modal notes as passing tones","One chord vamp is the best way to learn a mode''s sound. Loop a single Am7 chord and improvise in A Dorian for 10 minutes — the mode will imprint on your ear"]}',
   null, null, null, 80, 40, true),

  ('e1c70000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000007', 'Modal Chord Progressions',
   'Writing and recognizing progressions that establish a modal center rather than a traditional major/minor key.',
   5, 'theory',
   '{"intro":"A modal progression is one where the tonal center is not the I of a major key but another degree — making Dorian, Phrygian, or Mixolydian feel like home. This requires specific chord choices that reinforce the modal center.","steps":[{"title":"Dorian Progressions","body":"In D Dorian: Dm-G (i-IV) or Dm-Em (i-ii). The IV chord (G major) contains the natural 6th (B), which is the Dorian characteristic note. Avoid chords that establish D minor as Aeolian — specifically, do not use a dominant V chord (A7) which would pull to D minor. Instead, use the bVII-C major (C) or IV major (G) as dominant substitutes. Oye Como Va: Am7-D7 (i-IV in A Dorian)."},{"title":"Mixolydian Progressions","body":"In G Mixolydian: G-F-C-G (I-bVII-IV-I). The bVII chord (F major) contains the flat 7th (F), defining the Mixolydian sound. The progression avoids D7 (the V7 in G major) which would make it sound like traditional G major waiting to resolve. Instead, F major or D minor serve as the tension chords. Sweet Home Alabama: D-C-G (I-bVII-IV in D Mixolydian)."},{"title":"Phrygian Progressions","body":"In E Phrygian: Em-F (i-bII). The bII chord (F major) a half-step above the tonic is the defining Phrygian sound — exotic, dark, flamenco. Em-F-Em creates an unmistakable Phrygian vamp. Add G (bIII) for fullness. The bII-to-i resolution is the Phrygian equivalent of V-I."},{"title":"Aeolian (Natural Minor) Progressions","body":"Aeolian is the natural minor scale. Progressions: i-bVI-bVII (Am-F-G) or i-bVII-bVI (Am-G-F). The bVI and bVII chords are both major and do not contain the leading tone — there is no G# pulling to A. This absence of the leading tone is what distinguishes Aeolian from harmonic minor. Stairway to Heaven''s verse is Aeolian; All Along the Watchtower is Aeolian."}],"tips":["A modal progression avoids the V7-I cadence of the relative major — that resolution would pull the ear away from the desired modal center","To write a modal progression: establish the modal center chord on beat 1, include the chord that contains the mode''s characteristic note, and avoid the tonic''s own dominant 7th"]}',
   null, null, null, 0, 35, true);

-- ============================================================
-- CHAPTER 8: Blues Guitar Fundamentals
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, target_notes, accuracy_threshold, estimated_minutes, is_premium) values

  ('e1c80000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000008', '12-Bar Blues Structure',
   'The most important song form in American music — I-IV-V in 12 bars with endless variations.',
   1, 'theory',
   '{"intro":"The 12-bar blues is a chord progression, a song form, and a cultural touchstone. It is the foundation of blues, early rock and roll, jazz, and R&B. Understanding its structure and variations is essential for every guitarist.","steps":[{"title":"The Basic 12-Bar Form","body":"In the key of E: 4 bars of E7 (I7), 2 bars of A7 (IV7), 2 bars of E7 (I7), 1 bar of B7 (V7), 1 bar of A7 (IV7), 1 bar of E7 (I7), 1 bar of B7 (V7 — the turnaround). Count it: I-I-I-I / IV-IV-I-I / V-IV-I-V. This is the foundation. Internalize it. You will play and hear this form thousands of times."},{"title":"Quick Change Variation","body":"The quick change (or quick IV) replaces the second bar of I with IV. In E: E7 (1 bar), A7 (1 bar), E7 (2 bars), A7 (2 bars), E7 (2 bars), B7 (1 bar), A7 (1 bar), E7 (1 bar), B7 (1 bar). The IV chord arriving early adds harmonic momentum. Used in Rock and Roll Music (Chuck Berry) and countless others."},{"title":"Minor Blues","body":"In a minor blues, all chords become minor 7ths (or minor with flat 5 for the V). In Am: Am7 (4 bars), Dm7 (2 bars), Am7 (2 bars), Em7b5 (1 bar), Dm7 (1 bar), Am7 (1 bar), E7#9 (1 bar — the turnaround, often a dominant to pull back to Am). Minor blues is darker, more atmospheric. The Thrill Is Gone (B.B. King) is minor blues."},{"title":"Jazz Blues","body":"The jazz blues adds ii-V-I turnarounds and tritone substitutions. In C: C7-F7-C7-C7 / F7-F#dim-C7-A7 / Dm7-G7-C7-A7-Dm7-G7. Bar 6 often uses a diminished passing chord. Bars 9-10 use ii-V instead of V-IV. The last two bars are a I-VI-ii-V turnaround. This dense harmonic version is the Charlie Parker / bebop blues."}],"tips":["Learn to feel 12 bars — after 12 bars you should know instinctively where you are without counting. Practice with backing tracks that keep cycling","Every variation of the 12-bar blues still has the I-IV-V skeleton underneath. Know the skeleton first, then learn the variations"]}',
   null, null, null, 0, 30, true),

  ('e1c80000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000008', 'Shuffle Rhythm',
   'The swung eighth-note rhythm that defines blues — steady bass, swinging chords, locked-in groove.',
   2, 'exercise',
   '{"intro":"The shuffle is not just a rhythm — it is a feel. The bass walks, the chords swing, and the whole thing should make you want to move. Mastering the shuffle is mastering the heartbeat of the blues.","steps":[{"title":"The Basic Shuffle Strum","body":"In 4/4 time, play your strumming as swung eighth notes: DOWN-up DOWN-up DOWN-up DOWN-up, where the \"up\" lands on the third triplet subdivision. The hand moves continuously — down on the long subdivision, up on the short one. Over an E7 chord, maintain this swinging strum for 2 minutes without stopping. The wrist stays loose."},{"title":"The Boogie Bass Line","body":"While maintaining the shuffle strum on the treble strings, add a walking bass line with your thumb. Over E7: thumb plays string 6 open (E), then string 5 fret 2 (B), then string 4 fret 2 (E octave). This three-note bass riff played in shuffle time is the John Lee Hooker / boogie-woogie groove."},{"title":"Shuffle in A","body":"In A, the classic boogie pattern: string 5 open (A), string 4 fret 2 (E), string 4 fret 4 (F# passing tone), string 4 fret 2 (E back). This creates the loping A shuffle bass line. While the thumb does this, your index finger or a held chord rings the treble strings on beats 2 and 4 — creating a full band sound from one guitar."},{"title":"Tempo Control","body":"The shuffle lives or dies on tempo consistency. Start at 80 BPM. At 120 BPM and above, the shuffle naturally straightens slightly — this is correct and idiomatic. At 60 BPM, the shuffle should be wide and loping — almost exaggerated. Practice the same shuffle pattern at 60, 80, 100, and 120 BPM. Feel how the groove changes at each tempo."}],"tips":["Listen to the drummer, not yourself. In a blues band, the guitarist locks into the hi-hat pattern — that is where the shuffle lives","If you cannot tap your foot to your own shuffle, it is not swinging. The foot tap is the ultimate quality control for your groove"]}',
   null, null, null, 85, 35, true),

  ('e1c80000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000008', 'Blues Turnarounds',
   'The last two bars of the 12-bar form — classic turnaround licks and chord movements that bring the blues back home.',
   3, 'theory',
   '{"intro":"A turnaround is the harmonic and melodic passage at the end of a 12-bar blues that leads back to the top. It is the signature moment — where the guitarist announces \"here we go again\" with personality and style.","steps":[{"title":"The Classic V-IV-I-V Turnaround","body":"In E: last two bars — B7 (1 bar), A7 (half bar), E7 (half bar), B7 (last beat pickup). Play B7 with a sharp 9 (the Hendrix chord: x-2-1-2-3-x) on beat 4 for maximum blues flavor. This turnaround walks the bass down from B to A to E (strings 5 fret 2, string 5 open, string 6 open) while the treble voices stay put."},{"title":"The Chromatic Walkdown Turnaround","body":"In E: play a descending chromatic line on string 4 — E (fret 2), Eb (fret 1), D (open), then resolve to A (string 5 open). The chord shapes above this line: E7, E7/Eb (or a diminished passing chord), A7/E, then A7. This is the turnaround at the end of Pride and Joy and thousands of blues standards."},{"title":"The Diminished Passing Chord Turnaround","body":"Between IV and I, insert a #IVdim7 chord. In E: A7 (bar 10), A#dim7 (bar 10 beat 3, passing), E7/B (bar 11). The A#dim7 creates a dramatic chromatic lift: A to A# to B. This turnaround appears in jazz blues, ragtime, and sophisticated 12-bar arrangements."},{"title":"Single-Note Turnaround Licks","body":"In E, over bars 11-12, play the classic descending lick: string 1 fret 3 (G, bent up from G), string 2 fret 3 (D), string 2 open (B), string 3 fret 1 (G#), string 3 open (G), string 4 fret 2 (E). This pentatonic walk-down signals the end of the form and leads the listener back to the top effortlessly. Robert Johnson played a version of this. So did every blues guitarist since."}],"tips":["A turnaround should create forward momentum — it pulls the listener into the next chorus. If it feels like an ending, it is wrong","Learn three turnarounds in one key before moving to another — variety within one key is more useful than one turnaround in many keys"]}',
   null, null, null, 0, 30, true),

  ('e1c80000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000008', 'Classic Blues Licks',
   'Essential vocabulary — bends, slides, and phrases from the masters of electric blues.',
   4, 'exercise',
   '{"intro":"Blues licks are the common vocabulary of the genre — phrases that have been passed down, varied, and personalized by generations of guitarists. Learn the classics, then make them your own.","steps":[{"title":"The Albert King Bend","body":"Bend string 2 at fret 15 (D) a full step up to E, then release. This is the single most imitated bend in blues. Played with finger 3 and supported by fingers 1 and 2. The bend should be slow and vocal — do not rush to the target pitch. Hold it, vibrate it, then release. Albert King played this bend over and over in different contexts, and it never got old."},{"title":"The BB King Box","body":"The BB King box is a 4-fret region on strings 1 and 2. In A: string 2 frets 10 and 11, string 1 frets 10 and 12. These notes (D, D#/Eb, C, E) sit between major and minor pentatonic — the sweet spot where the blues ambiguity lives. BB King built his entire vocabulary from these four notes, using vibrato as the primary expressive tool."},{"title":"The SRV Shuffle Lick","body":"In E (open position): string 3 open (G), hammer-on to fret 2 (A), string 2 open (B), string 1 open (E), string 2 open (B), string 3 open (G). All open strings, fast triplet feel. This lick uses the open E, B, and G strings as a cascading melodic fragment that sounds impossibly fast but is physically simple — it is all open strings."},{"title":"The Muddy Waters Slide","body":"Slide into every chord. On A7: slide your whole chord shape (or a single note) from fret 1 to fret 2 (Bb to B, the major 3rd). The microtonal journey through the in-between pitches is pure blues. Muddy Waters''s entire guitar style is built on slides — sliding into notes, sliding between positions, never arriving clean but always arriving with feeling."}],"tips":["A lick is not a lick until you have played it 100 times. The first 90 repetitions build muscle memory. The last 10 build expression.","Every great blues guitarist sounds different playing the same lick. The notes are not the music — the timing, vibrato, attack, and decay are the music"]}',
   null, null, null, 80, 35, true),

  ('e1c80000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000008', 'Phrasing & Call-and-Response',
   'Structuring your soloing like a conversation — questions that demand answers, tension that seeks release.',
   5, 'exercise',
   '{"intro":"Great blues soloing is not about speed or complexity — it is about phrasing. The best blues guitarists treat every solo as a conversation with themselves, the band, and the listener.","steps":[{"title":"The Two-Bar Question, Two-Bar Answer","body":"Play a phrase (2 bars) that ends on an unresolved note — the flat 7th or the 9th tilted up (a microtonal bend). Then play an answering phrase (2 bars) that resolves to the root. The question creates tension. The answer releases it. Do this over a slow blues backing track. The silence between phrases is as important as the notes."},{"title":"Repetition with Variation","body":"Play a one-bar phrase. Repeat it exactly. Play it a third time but change one note — bend the last note instead of playing it straight, or change the rhythm slightly. This is how B.B. King built entire solos. The repetition tells the listener: pay attention. The variation tells them: here is the payoff."},{"title":"Space and Breath","body":"Play one note (the tonic, A on string 1 fret 5). Hold it for 4 full bars while the band cycles through. Use vibrato. Change the pick attack from soft to aggressive. Let the note decay naturally. This is the hardest exercise in this lesson — doing almost nothing while maintaining musical intensity. Miles Davis built a career on space."},{"title":"Trading Fours","body":"With a backing track or another musician: you play 4 bars, they play 4 bars. Respond to what they played — match their rhythmic pattern, echo their melodic shape, or answer their question. This is how jazz musicians develop improvisational dialogue. It forces you to listen more than you play."}],"tips":["Record your solos and transcribe your best phrases — your own vocabulary becomes the raw material for future solos","The best phrase is often the one you do not play. Leave a hole. Let the bass breathe. Let the listener fill in the gap"]}',
   null, null, null, 80, 35, true);

-- ============================================================
-- CHAPTER 9: Folk, Fingerstyle & Acoustic
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, target_notes, accuracy_threshold, estimated_minutes, is_premium) values

  ('e1c90000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000009', 'Open Tunings Introduction',
   'Beyond standard EADGBE — the open tunings that unlock new voicings, slide guitar, and folk textures.',
   1, 'theory',
   '{"intro":"Open tunings tune the guitar to a chord — strum all open strings and you hear a full chord. This transforms the fretboard geometry, enabling voicings, slide techniques, and harmonic colors impossible in standard tuning.","steps":[{"title":"What Is an Open Tuning?","body":"When the open strings (no frets pressed) form a full chord. Open G: D-G-D-G-B-D (low to high) — the G major chord with the 5th in the bass. Open D: D-A-D-F#-A-D — the D major chord. Open E: E-B-E-G#-B-E — the E major chord (same shape as open D but tuned up a whole step). Strumming all open strings produces a rich, ringing chord."},{"title":"Why Open Tunings Sound Different","body":"Standard tuning (EADGBE) is built for versatility — every chord is reachable but no chord comes for free. Open tunings sacrifice versatility for resonance. Because the open strings are already a chord, any barred fret gives you a major chord. Harmonics ring longer. The guitar becomes more resonant and overtone-rich."},{"title":"Open G (D-G-D-G-B-D)","body":"Tune strings 6, 5, and 4 down: E→D, A→G, D stays D. G, B, E stay the same. This is the Keith Richards tuning. Barre all strings at any fret for an instant major chord. The 5th string (G) is the root — melodies and riffs in G originate there. The open 5th and 6th strings create a droning, bagpipe-like effect."},{"title":"Open D (D-A-D-F#-A-D)","body":"Tune strings 6, 3, 2, and 1: E→D, G→F#, B→A, E→D. String 5 (A) stays. This is a versatile fingerstyle tuning with a wide, open, ringing quality. The root (D) is on strings 6, 4, and 1. The major 3rd (F#) is on string 3. Barre all strings at fret 5 for a G chord, fret 7 for A, fret 12 for D again."}],"tips":["When retuning, go slowly — drastic pitch changes stress the neck and strings. Tune down, then back up to pitch for stability","Learn one open tuning thoroughly before exploring others. Open G and open D cover most folk, blues slide, and fingerstyle repertoire"]}',
   null, null, null, 0, 30, true),

  ('e1c90000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000009', 'DADGAD Tuning',
   'The iconic Celtic and world-music tuning — neither major nor minor, suspended and ambiguous.',
   2, 'exercise',
   '{"intro":"DADGAD (D-A-D-G-A-D) is the signature tuning of British folk guitar (Bert Jansch, John Renbourn) and world music. Tuning to Dsus4 (D-A-D-G-A-D) creates an ambiguous tonality — neither major nor minor — that rings with drone-like resonance.","steps":[{"title":"Tuning to DADGAD","body":"From standard: tune string 6 down a whole step (E→D). String 2 down a whole step (B→A). String 1 down a whole step (E→D). Strings 5, 4, and 3 stay the same. The result: D-A-D-G-A-D. Strum all open strings — hear that suspended, ancient, modal quality? That is DADGAD. The tuning is Dsus4 — D major with no 3rd, the 4th (G) replacing it."},{"title":"Basic DADGAD Chords","body":"The open strings are your drone. D major: barre at fret 2 (strings 1-5) or finger fret 2 on strings 3, 4, 5 while leaving strings 1, 2, 6 open. D minor: fret 1 on string 3 (F instead of F#), all others open. G major: barre at fret 5 (or finger individual frets with open strings ringing). Note: chord shapes in DADGAD are entirely different from standard tuning — forget what you know and explore."},{"title":"The DADGAD Sound","body":"DADGAD naturally produces open, ringing, ambiguous chords. The two open D strings (6 and 4) drone continuously. The open G (string 3) and A (string 2) are the 4th and 5th of D — they create tension without resolution. This suspended quality is what makes DADGAD perfect for Celtic music, film scores, and atmospheric fingerstyle."},{"title":"A Simple DADGAD Piece","body":"Play this pattern with open strings throughout: thumb alternates D (string 4) and A (string 5). Index on string 3 open (G), middle on string 2 open (A), ring on string 1 open (D). Then move to a D5 shape: barre strings 1-3 at fret 2, thumb on open strings 5 and 4. This creates a simple, meditative two-chord pattern entirely unique to DADGAD."}],"tips":["DADGAD is a landscape, not a map — spend time exploring by ear before looking up chord charts. The open strings guide you","Keep a separate guitar in DADGAD if possible. Retuning every time creates a barrier to practice"]}',
   null, null, null, 85, 40, true),

  ('e1c90000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000009', 'Using a Capo',
   'The capo as a creative tool for transposition, voicing, and tonal variety — not a crutch.',
   3, 'theory',
   '{"intro":"The capo is not cheating — it is a tool that professional guitarists in every genre use for transposition, tone shaping, and harmonic creativity. Understanding capo logic makes you a more versatile and efficient musician.","steps":[{"title":"How a Capo Works","body":"The capo clamps across the fretboard, effectively moving the nut to a new position. Capo at fret 2: playing an open G shape now sounds as an A chord. The interval pattern of a G shape played at capo 2 is A major — not G major shifted up. The capo preserves the open-string voicing in a new key."},{"title":"Capo Transposition Chart","body":"Key of song minus capo fret equals shape you play. Example: song is in Bb. Place capo at fret 3. Bb minus 3 semitones = G. Play G shapes with capo at 3 — you are now in Bb. This is the capo calculation: (desired key) - (capo fret) = (shape to play). Count semitones: C-C#-D-Eb-E-F-F#-G-Ab-A-Bb-B. Bb is 10 semitones from C. Capo at 3 means you are 3 semitones up, so play shapes in G (7 semitones from C). 3 + 7 = 10 = Bb."},{"title":"Capo for Voicing Variety","body":"Play G-C-D in open position, then play the same chords with capo at fret 5 using D-G-A shapes, then with capo at fret 7 using C-F-G shapes. Same key, three different voicings. The higher the capo, the brighter and more mandolin-like the guitar sounds. Folk duos often use capos at different positions to create contrasting registers."},{"title":"Partial Capo (Cut Capo)","body":"A partial capo covers only strings 5-4-3 (or 4-3-2), leaving the outer strings open. This creates a DADGAD-like effect in standard tuning. Capo strings 5-4-3 at fret 2 while strings 6, 2, and 1 remain open: you have E-B-E-A-B-E — an Esus2 chord. Creative capo use is a signature of artists like Antoine Dufour and Phil Keaggy."}],"tips":["A good capo applies even pressure without pulling strings sharp — the Shubb, G7th, and Thalia capos are worth the investment over cheap spring-loaded models","When using a capo live, tune your guitar with the capo on to account for the slight pitch change it introduces"]}',
   null, null, null, 0, 25, true),

  ('e1c90000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000009', 'Folk Song Arrangements',
   'Turning a melody and chords into a complete fingerstyle arrangement — melody, bass, and harmony on one guitar.',
   4, 'exercise',
   '{"intro":"A folk song arrangement combines melody, bass, and chords into a single guitar performance. This is how one guitar can sound like a full ensemble — the art of the singer-songwriter and solo instrumentalist.","steps":[{"title":"Separate the Elements","body":"Choose a simple folk melody (Amazing Grace, Scarborough Fair). First, play only the melody on strings 1 and 2. Then play only the chords (Am, G, F, E). Then play only the bass notes (the lowest note of each chord). You must hear and feel each layer independently before you can combine them."},{"title":"Melody on Top, Bass Below","body":"Place the melody notes on the high strings (1 and 2) and assign the bass to your thumb on strings 6, 5, and 4. Play bass notes on beats 1 and 3. Play melody on beats where the melody falls. The spaces between melody notes are filled with chord tones (strings 2, 3, 4) played by i and m fingers. The arrangement emerges from the marriage of bass pulse and melodic contour."},{"title":"Chord Tones as Filler","body":"When the melody pauses, fill the space with arpeggiated chord tones. If the melody lands on a half note (2 beats), play the chord tones below it on the second beat. The arrangement breathes — melody forward, then a moment of harmonic color, then melody forward again. Do not fill every gap — silence is musical."},{"title":"Arranging a Complete Song","body":"Take a simple song like Danny Boy in G. Map the melody to strings 1 and 2. Map the bass to strings 6, 5, 4 following the chord roots. Write down every note for 8 bars. Practice phrase by phrase — 2 bars at a time. The arrangement should flow so naturally that a listener hears the song, not the technique."}],"tips":["Start with melodies you can sing — if you cannot sing the melody, you do not know it well enough to arrange it on guitar","The simplest arrangements are often the most beautiful. One melody note plus a ringing open string can be more powerful than notes every 16th"]}',
   null, null, null, 80, 40, true),

  ('e1c90000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000009', 'Acoustic Dynamics',
   'Controlling volume, tone, and attack on acoustic guitar — playing softly is harder than playing loudly.',
   5, 'exercise',
   '{"intro":"An acoustic guitar has no volume knob. All dynamics come from your hands — how hard you pluck, where you pluck, and how you let notes decay. Mastering dynamics is what separates competent playing from moving, expressive performance.","steps":[{"title":"The Five Dynamic Levels","body":"Define five levels of volume: pp (pianissimo, very soft), p (piano, soft), mf (mezzo-forte, medium), f (forte, loud), ff (fortissimo, very loud). Play a single open G string at each level. The difference between pp and ff should be dramatic — barely audible to room-filling. This is your dynamic range. Expand it."},{"title":"Sul Ponticello to Sul Tasto","body":"Pluck near the bridge (sul ponticello): the tone is thin, bright, metallic. Pluck over the soundhole: warm and full. Pluck near the 12th fret (sul tasto): soft, round, flute-like. Each position is a different \"tone\" on the same note. Practice playing a melody moving your right hand among these three zones for color variation."},{"title":"Crescendo and Decrescendo","body":"Pick a four-chord progression (Am-G-F-E). Play each chord once per bar, letting it ring. Bar 1: pp (barely audible strum). Bar 2: p to mf (building). Bar 3: f (full strum). Bar 4: ff to pp (loud attack that fades dramatically). The crescendo and decrescendo create a narrative arc — the listener is taken on a journey."},{"title":"Fingerstyle Dynamic Control","body":"Play the p-i-m-a arpeggio pattern over Am. Play it four times: first at pp, second at p, third at mf, fourth at f. Then play it once where p = loud, i = medium, m = soft, a = very soft — each finger a different dynamic. This is right-hand independence at its most refined. Classical guitarists spend years on this exercise."}],"tips":["Record yourself playing a simple passage at your normal volume, then listen back. Most players are surprised to find they play at a monotonous dynamic level — awareness is the first step","A rest with a slow fade-out of the previous note can be more dramatic than any fortissimo chord — dynamics are about contrast, not absolute volume"]}',
   null, null, null, 85, 35, true);

-- ============================================================
-- CHAPTER 10: Rhythm, Improv & Style
-- ============================================================
insert into public.lessons (id, chapter_id, title, description, order_index, type, content, target_chord, target_finger_positions, target_notes, accuracy_threshold, estimated_minutes, is_premium) values

  ('e1ca0000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000010', 'Improvisation Framework',
   'A structured approach to improvisation — connecting scales, chords, rhythm, and phrasing into a unified method.',
   1, 'theory',
   '{"intro":"Improvisation is not random — it is spontaneous composition guided by a framework. This lesson provides the mental model that professional musicians use to create coherent, compelling solos in real time.","steps":[{"title":"The Three-Layer Framework","body":"Layer 1 — Harmonic: what chords are playing? What are the chord tones (1-3-5-7)? Layer 2 — Scalar: what scale fits these chords? Pentatonic, major, minor, modes? Layer 3 — Rhythmic: what is the rhythmic feel? Straight, swing, triplet-based? An improvised solo is the intersection of these three layers. When in doubt, drop to Layer 1 — chord tones are always safe and musical."},{"title":"Target Notes on Downbeats","body":"The strongest notes in any solo are chord tones (1, 3, 5, 7) landing on beats 1 and 3. Practice improvising over a G-C-D progression where every downbeat note is a chord tone from the current chord. It will sound intentional and melodic even if the notes between downbeats are random. Target notes are your anchor."},{"title":"Motivic Development","body":"A motif is a short melodic idea — 3 to 7 notes. Create one motif. Play it. Repeat it. Vary it (change one note, change the rhythm, transpose it to a different scale degree). Fragment it (play only the first half). Extend it (add notes). This is how Beethoven, Coltrane, and Jerry Garcia all structured their improvisations — not note-by-note, but idea-by-idea."},{"title":"The Arc of a Solo","body":"A great solo has a shape: start sparse and low (lower strings, fewer notes, quieter). Build in density and register (more notes, higher on the neck, louder). Reach a peak (the most intense moment). Release (return to sparseness, land on the tonic). This arc — exposition, development, climax, resolution — is storytelling, not just note-playing. Plan your arc before you play your first note."}],"tips":["If you get lost during an improvised solo, stop playing for a bar, listen, and re-enter on the root. Silence is never wrong.","The quality of your improvisation is limited by the quality of your listening. Hear the band. Hear yourself. Respond."]}',
   null, null, null, 0, 30, true),

  ('e1ca0000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000010', 'Building a Solo',
   'Constructing a complete improvised solo over a chord progression — from first note to final resolution.',
   2, 'exercise',
   '{"intro":"This exercise guides you through building a complete solo from scratch. You will start with chord tones, add rhythm, incorporate scale passages, and shape the whole thing into a musical statement with a clear beginning, middle, and end.","steps":[{"title":"Step 1 — The Skeleton","body":"Over a backing track in G (G-Em-C-D, 4 bars each, slow at 70 BPM), play only the root note of each chord on beat 1 — one quarter note per bar. Do this for 2 full cycles (32 bars). This is your skeleton. It forces you to hear the chord changes and resist the urge to play notes. Discipline now enables freedom later."},{"title":"Step 2 — Add Chord Tones","body":"Now play the root on beat 1 and add the third or fifth on beat 3. For G: B (3rd) or D (5th). For Em: G (3rd) or B (5th). For C: E (3rd) or G (5th). For D: F# (3rd) or A (5th). You are building a two-note-per-bar solo — melodic, intentional, and perfectly in harmony with every chord."},{"title":"Step 3 — Add Rhythmic Variety","body":"Keep the same chord-tone vocabulary, but vary the rhythm. Play two eighth notes on beat 1, a quarter rest on beat 2, a syncopated figure on beats 3-4. Same notes, different rhythm. The solo now has motion. It breathes. Rhythmic variation with simple notes is more musical than complex notes with no rhythm."},{"title":"Step 4 — Introduce Scale Lines","body":"Now connect your chord tones with scale passages. Between the root of G and the third of Em, play a short G major scale run: G-A-B (string 3 frets 0-2-4). Between the fifth of D and the root of the returning G, play a descending run. The chord tones remain your pillars. The scale passages are the connective tissue."},{"title":"Step 5 — Add Expression and Space","body":"Take one note in your solo and bend it. Take another and add wide vibrato. Take a bar of complete silence. These expressive decisions transform correct notes into a personal statement. Record your final solo and listen back. Does it have an arc? Does it tell a story? If not, refine."}],"tips":["Building a solo step by step trains you to think in layers — once this is internalized, you will do all five steps simultaneously and without conscious effort","The backing track is your band. Listen to it more than you listen to yourself"]}',
   null, null, null, 80, 45, true),

  ('e1ca0000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000010', 'Jazz Comping Basics',
   'Rhythmic chord accompaniment in jazz — voice leading, extensions, and interactive comping behind a soloist.',
   3, 'theory',
   '{"intro":"Comping (from accompanying) is the art of playing chords behind a soloist or vocalist. In jazz, comping is a conversation — sparse, interactive, and rhythmically alive. It is the opposite of strumming a fixed pattern.","steps":[{"title":"The Freddie Green Approach","body":"Freddie Green (Count Basie Orchestra) defined comping as four even quarter-note strums per bar on every beat: chunk-chunk-chunk-chunk. The chords are voiced with just two or three notes — root on string 6 or 5, plus one or two color tones (3rd and 7th). The strum is short, percussive, and left-hand damped. This provides the unwavering pulse behind the band."},{"title":"Guide Tones: The 3rd and 7th","body":"The 3rd and 7th of a chord define its quality and function. Over a ii-V-I in C (Dm7-G7-Cmaj7): Dm7 guide tones are F (3rd) and C (7th). G7 guide tones are B (3rd) and F (7th). Cmaj7 guide tones are E (3rd) and B (7th). Notice: F is the 7th of Dm7 and the 7th of G7 — it stays. B is the 3rd of G7 and the 7th of Cmaj7 — it stays. Guide tones move by half-step or stay put. Comp using only 3rds and 7ths on strings 3 and 4 — the essence of the harmony."},{"title":"Rhythmic Comping Patterns","body":"Classic jazz comping rhythms: the Charleston (beat 1, and-of-2), the reverse Charleston (and-of-1, beat 3), and the anticipatory hit (and-of-4 leading into the next chord). Your comping should react to the soloist — comp busily when the soloist rests, lay out (stop playing) when the soloist peaks. It is a conversation, not a monologue."},{"title":"Shell Voicings","body":"A shell voicing is a three-note chord: root, 3rd, and 7th (omit the 5th). For Dm7: D (string 5 fret 5), F (string 4 fret 3), C (string 3 fret 5). For G7: G (string 6 fret 3), B (string 4 fret 2), F (string 3 fret 3). Shell voicings are the foundation of jazz guitar harmony — every extended voicing builds on them. Master shell voicings for all seventh chords around the cycle of fourths."}],"tips":["The best comping is barely noticeable — it supports without demanding attention. If the soloist turns around to look at you, you are playing too much","Learn one new jazz standard per month. Comp through the changes with shell voicings. The repertoire is your textbook"]}',
   null, null, null, 0, 35, true),

  ('e1ca0000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000010', 'Finding Your Voice',
   'Transcending technique to develop a personal musical identity — what makes you sound like you.',
   4, 'theory',
   '{"intro":"Technique gives you options. Your voice is which options you choose. This lesson is about developing taste — the discernment that makes your playing recognizable and personal, not just technically correct.","steps":[{"title":"Influences, Not Imitation","body":"List five guitarists you love. For each, identify exactly what you love: the vibrato of BB King? The rhythmic feel of Nile Rodgers? The note choice of David Gilmour? The sonic textures of The Edge? Now practice each of these specific elements in isolation. You are not trying to copy the guitarist — you are extracting a technique or approach and making it your own."},{"title":"Your Signature Techniques","body":"What do you do that feels natural and sounds distinctive? Maybe you naturally bend with wide, slow vibrato. Maybe your thumb instinctively finds walking bass lines. Maybe you hear melodies in a particular register. Lean into these natural tendencies — they are the seeds of your voice. Technique that you struggle with may never be part of your sound, and that is fine."},{"title":"Limitation as a Creative Tool","body":"Restrict yourself intentionally. Improvise using only two strings. Compose using only three chords. Play a solo with only one note — and make it compelling through rhythm and dynamics. Limitations force creativity. Django Reinhardt played with two working fingers on his left hand. The constraint created the style."},{"title":"Recording and Self-Critique","body":"Record yourself playing freely for 10 minutes — no click, no plan, just playing. Listen back a day later with a notebook. What patterns do you keep repeating? What sounds good? What sounds like someone else? Your unconscious voice appears when you stop trying to sound good and just sound. The recording does not lie."}],"tips":["Your voice is not something you find — it is something you reveal by removing everything that is not you. Play less. Listen more.","The most distinctive guitarists are not the most technically proficient — they are the most themselves. Tom Morello, Neil Young, Kurt Cobain. All instantly recognizable within two notes"]}',
   null, null, null, 0, 30, true),

  ('e1ca0000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000010', 'Performance Practice',
   'Preparing to play for others — mindset, rehearsal strategies, stage setup, and recovering from mistakes.',
   5, 'exercise',
   '{"intro":"Playing for an audience — even an audience of one — is a different skill from playing in your bedroom. This lesson prepares you for performance: mental preparation, practical rehearsal, and the grace to recover when things go wrong.","steps":[{"title":"Rehearsal vs Practice","body":"Practice fixes problems — you stop, repeat, drill. Rehearsal simulates performance — you never stop. Schedule dedicated rehearsal sessions where you play your set from start to finish without pausing for mistakes. Record it. Identify the moments that fell apart, then practice those transitions in your next practice session. Rehearsal reveals what practice missed."},{"title":"The Three-Times Rule","body":"A piece is performance-ready when you can play it three times in a row without significant errors. Not once — three times. The first time proves you can play it. The second proves it was not luck. The third proves consistency. If you cannot pass the three-times rule in your bedroom, the stage will expose every weak point."},{"title":"Mistake Recovery","body":"In performance, mistakes happen. The difference between amateurs and professionals is not error-free playing — it is recovery. When you hit a wrong note: do not stop, do not make a face, do not apologize. Keep going. The audience forgets a wrong note. They never forget a performer who stops. Practice recovering by having someone randomly mute a string while you play — learn to continue no matter what."},{"title":"Stage Presence Fundamentals","body":"Before your first note: take three deep breaths. Look at the audience. Smile. Tune quickly and quietly. Count in (in your head or aloud). After your last note: let it ring. Hold the silence for two seconds. Then lower your hands. Then acknowledge the audience. The silence between songs is part of the performance — do not rush to fill it."},{"title":"Recording a Performance Video","body":"Set up your phone and record yourself performing one song as if for an audience. No retakes. No stopping. Watch it back. What do you notice about your body language? Your facial expression? The pacing? Performing for the camera is the closest simulation to performing for people — the red recording light triggers the same adrenaline response."}],"tips":["The audience wants you to succeed. They are on your side. Nervousness is just excitement without breath — breathe deeply and it transforms into energy","Perform for one person before you perform for ten. A small, supportive audience builds confidence more effectively than a large, anonymous one"]}',
   null, null, null, 85, 40, true);
